#!/usr/bin/env python3
"""
init-workflow.py — Generate per-step subagent files for a workflow.

For each step with subagent: true, writes
.claude/agents/<workflow>-<step>/AGENT.md with the correct tools whitelist
(built-ins + script tools from workflow_tools loader + mcp tools from
declared servers).

Usage:
    python .agent/scripts/init-workflow.py <workflow-name>

Exit codes:
    0 — success (files written or already up-to-date)
    1 — workflow not found
    2 — workflow.yaml malformed
    3 — file write error

Output: human-readable summary on stdout describing what was created,
updated, or already up-to-date. Always tells the user to restart Claude
Code if any files were modified.
"""

import argparse
import glob as glob_module
import hashlib
import json
import os
import re
import sys


# ── Constants ──

AGENT_DIR = ".agent"
WORKFLOWS_DIR = os.path.join(AGENT_DIR, "workflows")
TEMPLATES_DIR = os.path.join(WORKFLOWS_DIR, "templates")

CLAUDE_AGENTS_DIR = os.path.join(".claude", "agents")
WORKFLOW_TOOLS_PREFIX = "mcp__workflow_tools__"
DEFAULT_BUILTINS = ["Read", "Write", "Edit", "Bash", "Glob", "Grep"]

# Standard hooks block — file-guard for engine file protection plus
# workflow-tool-validator for script tool input schema enforcement.
# Both hooks short-circuit when they don't apply (no-op), so they are
# safe to attach to every per-step subagent unconditionally.
STANDARD_HOOKS = """hooks:
  PreToolUse:
    - matcher: "Edit|Write"
      hooks:
        - type: command
          command: "python .agent/scripts/file-guard.py"
    - matcher: "mcp__workflow_tools__.*"
      hooks:
        - type: command
          command: "python .agent/scripts/workflow-tool-validator.py"
"""

GENERATED_MARKER = "# Auto-generated by init-workflow.py — DO NOT EDIT MANUALLY"


# ── YAML loading ──

def _get_yaml():
    try:
        import yaml
        return yaml
    except ImportError:
        sys.stderr.write(
            "ERROR: PyYAML is required for init-workflow.py "
            "(pip install pyyaml)\n"
        )
        sys.exit(2)


def _load_workflow(name):
    """Find and load workflow.yaml by name. Returns (path, data) or raises."""
    yaml = _get_yaml()
    candidates = [
        os.path.join(TEMPLATES_DIR, "my_workflows", name, "workflow.yaml"),
        os.path.join(TEMPLATES_DIR, "predefined", name, "workflow.yaml"),
        os.path.join(TEMPLATES_DIR, "examples", name, "workflow.yaml"),
        os.path.join(WORKFLOWS_DIR, name, "workflow.yaml"),
    ]
    for path in candidates:
        if os.path.isfile(path):
            with open(path, "r", encoding="utf-8") as f:
                return path, yaml.safe_load(f)
    raise FileNotFoundError(
        f"Workflow '{name}' not found. Searched:\n  " +
        "\n  ".join(candidates)
    )


# ── Naming ──

def _normalize(s):
    """Convert hyphens/non-word chars to underscores (matches loader)."""
    return re.sub(r"[^a-zA-Z0-9_]", "_", s)


def _subagent_dir(workflow_name, step_name):
    """Return the .claude/agents/ directory name for a (workflow, step)."""
    return f"{workflow_name}-{step_name}"


def _script_tool_mcp_name(workflow_name, tool_name):
    """Build the MCP tool name for a script tool: mcp__workflow_tools__<wf>__<tool>."""
    return (
        WORKFLOW_TOOLS_PREFIX
        + _normalize(workflow_name)
        + "__"
        + _normalize(tool_name)
    )


def _mcp_server_tool_name(server_name, tool_name):
    """Build the MCP tool name for an external mcp server tool."""
    return f"mcp__{_normalize(server_name)}__{_normalize(tool_name)}"


# ── Tool resolution ──

def _resolve_step_tools(workflow, step):
    """Determine the list of MCP tool names this step's subagent needs.

    Returns a list of fully-qualified MCP tool name strings.
    Built-ins are added separately by the caller.

    Resolution rules:
      - step.tools: optional list of names referencing workflow.tools entries
      - if absent → step uses ALL workflow tools
      - script tools → mcp__workflow_tools__<wf>__<name>
      - mcp tools → enumerate via expected_tools field (or empty)
    """
    wf_tools = workflow.get("tools", []) or []
    wf_name = workflow.get("name", "")

    step_tools_filter = step.get("tools")
    if step_tools_filter:
        active = [t for t in wf_tools if t.get("name") in step_tools_filter]
    else:
        active = wf_tools

    mcp_names = []
    for tool_def in active:
        ttype = tool_def.get("type")
        tname = tool_def.get("name")
        if not tname:
            continue

        if ttype == "script":
            mcp_names.append(_script_tool_mcp_name(wf_name, tname))

        elif ttype == "mcp":
            # mcp type tools: need explicit list of tool names from the server.
            # Convention: workflow.yaml may include `expected_tools: [...]` on
            # the mcp tool entry. Without it, no tools are whitelisted (the
            # subagent will not see any tools from this server). The user can
            # add expected_tools to fix.
            expected = tool_def.get("expected_tools") or []
            for sub_tool in expected:
                mcp_names.append(_mcp_server_tool_name(tname, sub_tool))

    return mcp_names


def _has_subagent_steps(workflow):
    """Return list of (step_name, step_dict) for steps with subagent: true."""
    out = []
    for step in workflow.get("steps", []) or []:
        if step.get("subagent", True) is not False:  # default True
            out.append((step.get("name"), step))
    return out


# ── AGENT.md generation ──

def _build_agent_md(workflow, step):
    """Build the full AGENT.md content for a (workflow, step) subagent."""
    wf_name = workflow.get("name", "")
    step_name = step.get("name", "")
    sub_name = _subagent_dir(wf_name, step_name)

    mcp_tools = _resolve_step_tools(workflow, step)
    all_tools = DEFAULT_BUILTINS + mcp_tools
    tools_line = "tools: " + ", ".join(all_tools)

    description = (
        f"Workflow step subagent for '{step_name}' step of '{wf_name}' workflow. "
        f"Auto-generated — do not edit manually."
    )

    body = f"""You are executing step '{step_name}' of workflow '{wf_name}'.

## Your responsibilities

1. **Follow the goal** provided in the user message precisely
2. **Write outputs** to the paths specified in the goal
3. **Read inputs** listed in the goal for context
4. **Use the script/MCP tools** declared for this step — they are in your tool inventory
5. **Do not modify** engine infrastructure files — a PreToolUse hook enforces this

## Output quality

- **Follow struct schemas exactly.** Output must match the schema specified in the goal.
- Write to the **exact file path** specified.
- Use the declared tools for their intended purpose; do not invent shortcuts.

## What happens after you finish

A structural gate validates your outputs. If validation fails, you receive feedback
and should fix the issues. If it passes, the orchestrator proceeds to the next step.
"""

    frontmatter = (
        "---\n"
        f"name: {sub_name}\n"
        f"description: {description}\n"
        "model: inherit\n"
        f"{tools_line}\n"
        "maxTurns: 100\n"
        f"{STANDARD_HOOKS}"
        "---\n"
    )

    return frontmatter + "\n" + GENERATED_MARKER + "\n\n" + body


# ── File operations ──

def _content_hash(text):
    return hashlib.sha256(text.encode("utf-8")).hexdigest()


def _write_subagent(workflow, step, dry_run=False):
    """Write or update one per-step subagent. Returns ('created', 'updated', 'unchanged')."""
    wf_name = workflow.get("name", "")
    step_name = step.get("name", "")
    sub_dir_name = _subagent_dir(wf_name, step_name)
    sub_dir = os.path.join(CLAUDE_AGENTS_DIR, sub_dir_name)
    sub_path = os.path.join(sub_dir, "AGENT.md")

    new_content = _build_agent_md(workflow, step)

    existing_content = None
    if os.path.isfile(sub_path):
        try:
            with open(sub_path, "r", encoding="utf-8") as f:
                existing_content = f.read()
        except OSError:
            existing_content = None

    if existing_content == new_content:
        return "unchanged", sub_dir_name

    status = "updated" if existing_content is not None else "created"

    if not dry_run:
        os.makedirs(sub_dir, exist_ok=True)
        with open(sub_path, "w", encoding="utf-8") as f:
            f.write(new_content)

    return status, sub_dir_name


def _find_orphan_subagents(workflow_name, expected_dir_names):
    """Find subagent dirs with this workflow's prefix that aren't in expected list."""
    if not os.path.isdir(CLAUDE_AGENTS_DIR):
        return []
    prefix = f"{workflow_name}-"
    found = []
    for entry in sorted(os.listdir(CLAUDE_AGENTS_DIR)):
        if entry.startswith(prefix) and entry not in expected_dir_names:
            full_path = os.path.join(CLAUDE_AGENTS_DIR, entry)
            if os.path.isdir(full_path):
                # Verify it's an auto-generated one before deleting
                agent_md = os.path.join(full_path, "AGENT.md")
                if os.path.isfile(agent_md):
                    try:
                        with open(agent_md, "r", encoding="utf-8") as f:
                            content = f.read()
                        if GENERATED_MARKER in content:
                            found.append(entry)
                    except OSError:
                        pass
    return found


def _delete_orphan(name, dry_run=False):
    """Delete an orphan subagent directory and its AGENT.md."""
    full_path = os.path.join(CLAUDE_AGENTS_DIR, name)
    agent_md = os.path.join(full_path, "AGENT.md")
    if not dry_run:
        try:
            if os.path.isfile(agent_md):
                os.remove(agent_md)
            os.rmdir(full_path)
        except OSError as e:
            sys.stderr.write(f"Failed to delete {full_path}: {e}\n")


# ── Main ──

def init_workflow(name, dry_run=False):
    """Generate/update per-step subagent files for one workflow.

    Returns dict with keys: created, updated, unchanged, deleted, total.
    """
    try:
        wf_path, workflow = _load_workflow(name)
    except FileNotFoundError as e:
        sys.stderr.write(f"ERROR: {e}\n")
        sys.exit(1)
    except Exception as e:
        sys.stderr.write(f"ERROR: failed to parse workflow.yaml: {e}\n")
        sys.exit(2)

    if not isinstance(workflow, dict):
        sys.stderr.write(f"ERROR: workflow.yaml is not a mapping: {wf_path}\n")
        sys.exit(2)

    wf_name = workflow.get("name") or name
    print(f"Workflow: {wf_name} ({wf_path})")

    subagent_steps = _has_subagent_steps(workflow)
    if not subagent_steps:
        print("  No subagent steps. Nothing to generate.")
        return {"created": [], "updated": [], "unchanged": [], "deleted": [], "total": 0}

    created, updated, unchanged = [], [], []
    expected_dir_names = []

    for step_name, step in subagent_steps:
        if not step_name:
            sys.stderr.write("WARNING: step without name; skipping\n")
            continue
        try:
            status, dir_name = _write_subagent(workflow, step, dry_run=dry_run)
        except OSError as e:
            sys.stderr.write(f"ERROR: failed to write subagent for {step_name}: {e}\n")
            sys.exit(3)
        expected_dir_names.append(dir_name)
        if status == "created":
            created.append(dir_name)
            print(f"  CREATED  {dir_name}")
        elif status == "updated":
            updated.append(dir_name)
            print(f"  UPDATED  {dir_name}")
        else:
            unchanged.append(dir_name)
            print(f"  UNCHANGED {dir_name}")

    # Cleanup orphans (steps removed from workflow.yaml since last init)
    orphans = _find_orphan_subagents(wf_name, expected_dir_names)
    deleted = []
    for orphan in orphans:
        _delete_orphan(orphan, dry_run=dry_run)
        deleted.append(orphan)
        print(f"  DELETED  {orphan} (orphan)")

    total = len(created) + len(updated) + len(deleted)
    print()
    print(f"Summary: {len(created)} created, {len(updated)} updated, "
          f"{len(unchanged)} unchanged, {len(deleted)} deleted")

    if total > 0:
        print()
        print("[!] Restart Claude Code to load the new/updated subagents.")
        print("    After restart, you can run: /run-workflow " + wf_name)

    return {
        "created": created,
        "updated": updated,
        "unchanged": unchanged,
        "deleted": deleted,
        "total": total,
    }


def main():
    parser = argparse.ArgumentParser(
        description="Generate per-step subagent files for a workflow."
    )
    parser.add_argument("name", help="Workflow name")
    parser.add_argument(
        "--dry-run",
        action="store_true",
        help="Show what would be done without writing files",
    )
    args = parser.parse_args()

    init_workflow(args.name, dry_run=args.dry_run)


if __name__ == "__main__":
    main()
